# Collapse

## Import

```jsx live=false
import { Collapse } from '@node-real/bee';
```

## Usage

### Collapse transition

```jsx
function CollapseEx() {
  const { isOpen, onToggle } = useDisclosure();

  return (
    <>
      <Button onClick={onToggle}>Click Me</Button>
      <Collapse in={isOpen} animateOpacity>
        <Box p={40} color="white" mt="12" bg="scene.success.normal" borderRadius={8}>
          Some Text
        </Box>
      </Collapse>
    </>
  );
}
```

### Changing the startingHeight

```jsx
function Example() {
  const [show, setShow] = React.useState(false);

  const handleToggle = () => setShow(!show);

  return (
    <>
      <Collapse startingHeight={20} in={show}>
        Anim pariatur cliche reprehenderit, enim eiusmod high life accusamus terry richardson ad
        squid. Nihil anim keffiyeh helvetica, craft beer labore wes anderson cred nesciunt sapiente
        ea proident.
      </Collapse>
      <Button onClick={handleToggle} mt={12}>
        Show {show ? 'Less' : 'More'}
      </Button>
    </>
  );
}
```

